.gradient-box {
  background: linear-gradient(to right, #6a11cb, #2575fc);
}

body {
  font-family: 'Open Sans', Arial, sans-serif;
}

code {
  font-family: 'Courier New', Courier, monospace;
}

em {
  font-style: italic;
}

.caption {
  font-style: italic;
  color: #666;
}

a {
  text-decoration: none;
  color: #0066cc;
}

.deleted {
  text-decoration: line-through;
  color: #999;
}

.card-grid {
  display: flex;
  flex-direction: row;
  gap: 16px;
}

.stack {
  display: flex;
  flex-direction: column;
}

.navbar {
  display: flex;
  justify-content: space-between;
}

.centred {
  display: flex;
  justify-content: center;
}

.card-grid {
  display: flex;
  flex-wrap: wrap;
  gap: 24px;
}

.grid {
  display: grid;
  gap: 16px 32px;
}

.grid {
  display: grid;
  grid-template-columns: repeat(3, 1fr);
  gap: 24px;
}

.layout {
  display: grid;
  grid-template-columns: 250px 1fr;
}

.page {
  display: grid;
  grid-template-rows: auto 1fr auto;
  min-height: 100vh;
}

.tooltip {
  position: absolute;
  top: 100%;
  left: 0;
}

.sticky-nav {
  position: sticky;
  top: 0;
}

.dropdown {
  position: absolute;
  top: 100%;
  left: 0;
  background: white;
}

.modal {
  position: fixed;
  z-index: 1000;
}

.overlay {
  position: fixed;
  z-index: 999;
}

.scroll-box {
  height: 200px;
  overflow-y: auto;
  border: 1px solid #ccc;
}

.image-crop {
  overflow: hidden;
  border-radius: 50%;
}

.button {
  background-color: #0066cc;
  transition: background-color 0.3s ease, transform 0.2s ease;
}

.button:hover {
  background-color: #0055aa;
  transform: translateY(-2px);
}

@keyframes fadeIn {
  from { opacity: 0; }
  to { opacity: 1; }
}

.intro {
  animation: fadeIn 1s ease forwards;
}

.card:hover {
  transform: translateY(-4px);
  box-shadow: 0 8px 24px rgba(0,0,0,0.2);
}

.icon.spin {
  transform: rotate(360deg);
}

nav ul {
  list-style: none;
  padding: 0;
  margin: 0;
  display: flex;
  gap: 16px;
}

:focus-visible {
  outline: 3px solid #0066cc;
  outline-offset: 2px;
}

/* Don't do this without a replacement focus style */
/* button { outline: none; } */

.tooltip {
  visibility: hidden;
  opacity: 0;
  transition: opacity 0.2s;
}

.parent:hover .tooltip {
  visibility: visible;
  opacity: 1;
}

.label {
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
}
